import Foundation

enum AnalyticsEvent {
    case authenticationFlowStarted(userID: String)
    case authenticationFlowCompleted(userID: String)
    case apiCallMade(url: URL, requestPayload: Data?)
    case apiCallReceived(responsePayload: Data?, error: Error?)
    case userDataChanged(key: String, oldValue: Any?, newValue: Any?)
    case errorOccurred(error: Error)
}

class AnalyticsManager {
    static let shared = AnalyticsManager()
    
    private init() {}
    
    func log(event: AnalyticsEvent) {
        switch event {
        case .authenticationFlowStarted(let userID):
            NSLog("Authentication flow started for user ID: \(userID)")
        case .authenticationFlowCompleted(let userID):
            NSLog("Authentication flow completed for user ID: \(userID)")
        case .apiCallMade(let url, let requestPayload):
            if let payload = requestPayload {
                print("API call made to URL: \(url) with payload: \(String(data: payload, encoding: .utf8 ?? ""))")
            } else {
                NSLog("API call made to URL: \(url) with no payload")
            }
        case .apiCallReceived(let responsePayload, let error):
            if let payload = responsePayload {
                print("API call received with payload: \(String(data: payload, encoding: .utf8 ?? ""))")
            } else if let error = error {
                NSLog("API call failed with error: \(error.localizedDescription)")
            }
        case .userDataChanged(let key, let oldValue, let newValue):
            print("User data changed for key: \(key), old value: \(oldValue ?? "nil"), new value: \(newValue ?? "nil")")
        case .errorOccurred(let error):
            NSLog("Error occurred: \(error.localizedDescription)")
        }
    }
}

